/**
 * AMS Preference Centre — Front-end JS.
 *
 * Reads subscriber token from cookie (ams_subscriber_token),
 * loads current preferences, handles save + unsubscribe-all.
 */
(function () {
    'use strict';

    function getCookie(name) {
        var match = document.cookie.match(new RegExp('(?:^|; )' + name.replace(/([.$?*|{}()[\]\\/+^])/g, '\\$1') + '=([^;]*)'));
        return match ? decodeURIComponent(match[1]) : '';
    }

    function init() {
        var containers = document.querySelectorAll('[data-ams-prefcentre]');
        if (!containers.length) return;

        var token = getCookie('ams_subscriber_token');

        containers.forEach(function (container) {
            var saveBtn    = container.querySelector('.ams-prefcentre-save');
            var statusEl   = container.querySelector('.ams-prefcentre-status');
            var unsubLink  = container.querySelector('.ams-prefcentre-unsub-link');
            var emailInput = container.querySelector('input[name="email_opt_in"]');
            var smsInput   = container.querySelector('input[name="sms_opt_in"]');

            // Load current preferences if we have a token.
            if (token) {
                loadPreferences(token, emailInput, smsInput);
            }

            if (saveBtn) {
                saveBtn.addEventListener('click', function () {
                    if (!token) {
                        showStatus(statusEl, 'Unable to identify your subscription. Please use the link from your email.', true);
                        return;
                    }
                    var prefs = {};
                    if (emailInput) prefs.email_opt_in = emailInput.checked;
                    if (smsInput)   prefs.sms_opt_in   = smsInput.checked;

                    saveBtn.disabled = true;
                    saveBtn.textContent = 'Saving...';

                    fetch(amsPreferenceCentre.restUrl + 'ams/v1/forms/submit', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({
                            action: 'update_preferences',
                            subscriber_token: token,
                            preferences: prefs
                        })
                    })
                    .then(function (r) { return r.json(); })
                    .then(function (data) {
                        saveBtn.disabled = false;
                        saveBtn.textContent = amsPreferenceCentre.saveText || 'Save Preferences';
                        if (data.success !== false) {
                            showStatus(statusEl, 'Your preferences have been saved.', false);
                        } else {
                            showStatus(statusEl, data.message || 'Something went wrong. Please try again.', true);
                        }
                    })
                    .catch(function () {
                        saveBtn.disabled = false;
                        saveBtn.textContent = amsPreferenceCentre.saveText || 'Save Preferences';
                        showStatus(statusEl, 'Network error. Please try again.', true);
                    });
                });
            }

            if (unsubLink) {
                unsubLink.addEventListener('click', function (e) {
                    e.preventDefault();
                    if (!token) {
                        showStatus(statusEl, 'Unable to identify your subscription.', true);
                        return;
                    }
                    if (!confirm('Are you sure you want to unsubscribe from all communications?')) return;

                    fetch(amsPreferenceCentre.restUrl + 'ams/v1/forms/submit', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({
                            action: 'unsubscribe_all',
                            subscriber_token: token
                        })
                    })
                    .then(function (r) { return r.json(); })
                    .then(function (data) {
                        if (data.success !== false) {
                            if (emailInput) emailInput.checked = false;
                            if (smsInput)   smsInput.checked   = false;
                            showStatus(statusEl, 'You have been unsubscribed from all communications.', false);
                        } else {
                            showStatus(statusEl, data.message || 'Something went wrong.', true);
                        }
                    })
                    .catch(function () {
                        showStatus(statusEl, 'Network error. Please try again.', true);
                    });
                });
            }
        });
    }

    function loadPreferences(token, emailInput, smsInput) {
        fetch(amsPreferenceCentre.restUrl + 'ams/v1/forms/active?subscriber_token=' + encodeURIComponent(token))
            .then(function (r) { return r.json(); })
            .then(function (data) {
                if (data && data.preferences) {
                    if (emailInput && typeof data.preferences.email_opt_in !== 'undefined') {
                        emailInput.checked = !!data.preferences.email_opt_in;
                    }
                    if (smsInput && typeof data.preferences.sms_opt_in !== 'undefined') {
                        smsInput.checked = !!data.preferences.sms_opt_in;
                    }
                }
            })
            .catch(function () { /* silently fail */ });
    }

    function showStatus(el, message, isError) {
        if (!el) return;
        el.textContent = message;
        el.style.color = isError ? '#d63638' : '';
        el.classList.add('ams-visible');
        setTimeout(function () {
            el.classList.remove('ams-visible');
        }, 5000);
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();
